'use server';

import { prisma } from '@/lib/prisma';
import { revalidatePath } from 'next/cache';

export type Priority = 'low' | 'medium' | 'high';

export interface CreateTodoInput {
  title: string;
  description?: string;
  priority?: Priority;
  dueDate?: Date;
}

export interface UpdateTodoInput {
  id: string;
  title?: string;
  description?: string;
  completed?: boolean;
  priority?: Priority;
  dueDate?: Date;
}

export async function getTodos() {
  try {
    const todos = await prisma.todo.findMany({
      orderBy: [
        { completed: 'asc' },
        { createdAt: 'desc' },
      ],
    });
    return { success: true, data: todos };
  } catch (error) {
    console.error('Failed to fetch todos:', error);
    return { success: false, error: 'Failed to fetch todos' };
  }
}

export async function createTodo(input: CreateTodoInput) {
  try {
    const todo = await prisma.todo.create({
      data: {
        title: input.title,
        description: input.description,
        priority: input.priority || 'medium',
        dueDate: input.dueDate,
      },
    });
    revalidatePath('/');
    return { success: true, data: todo };
  } catch (error) {
    console.error('Failed to create todo:', error);
    return { success: false, error: 'Failed to create todo' };
  }
}

export async function updateTodo(input: UpdateTodoInput) {
  try {
    const { id, ...data } = input;
    const todo = await prisma.todo.update({
      where: { id },
      data,
    });
    revalidatePath('/');
    return { success: true, data: todo };
  } catch (error) {
    console.error('Failed to update todo:', error);
    return { success: false, error: 'Failed to update todo' };
  }
}

export async function deleteTodo(id: string) {
  try {
    await prisma.todo.delete({
      where: { id },
    });
    revalidatePath('/');
    return { success: true };
  } catch (error) {
    console.error('Failed to delete todo:', error);
    return { success: false, error: 'Failed to delete todo' };
  }
}

export async function toggleTodo(id: string) {
  try {
    const todo = await prisma.todo.findUnique({
      where: { id },
    });

    if (!todo) {
      return { success: false, error: 'Todo not found' };
    }

    const updated = await prisma.todo.update({
      where: { id },
      data: { completed: !todo.completed },
    });

    revalidatePath('/');
    return { success: true, data: updated };
  } catch (error) {
    console.error('Failed to toggle todo:', error);
    return { success: false, error: 'Failed to toggle todo' };
  }
}

import { getTodos } from './actions/todos';
import TodoList from './components/TodoList';
import TodoForm from './components/TodoForm';

export default async function Home() {
  const result = await getTodos();
  const todos = result.success && result.data ? result.data : [];

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100">
      <div className="container mx-auto px-4 py-8 max-w-4xl">
        <header className="mb-8">
          <h1 className="text-4xl font-bold text-gray-900 mb-2">My Todo List</h1>
          <p className="text-gray-700">Stay organized and productive</p>
        </header>

        <div className="grid gap-6 md:grid-cols-2">
          <div className="bg-white rounded-lg shadow-md p-6">
            <h2 className="text-xl font-semibold mb-4 text-gray-800">Add New Todo</h2>
            <TodoForm />
          </div>

          <div className="bg-white rounded-lg shadow-md p-6">
            <h2 className="text-xl font-semibold mb-4 text-gray-800">Your Todos</h2>
            <TodoList todos={todos} />
          </div>
        </div>
      </div>
    </div>
  );
}

